import{_ as t,o as a,c as o,a1 as i}from"./chunks/framework.DdbKPUhY.js";const u=JSON.parse('{"title":"✦ Frequently Asked Questions","description":"","frontmatter":{},"headers":[],"relativePath":"faq.md","filePath":"faq.md"}'),n={name:"faq.md"};function r(s,e,l,d,p,c){return a(),o("div",null,[...e[0]||(e[0]=[i(`<h1 id="✦-frequently-asked-questions" tabindex="-1">✦ Frequently Asked Questions <a class="header-anchor" href="#✦-frequently-asked-questions" aria-label="Permalink to &quot;✦ Frequently Asked Questions&quot;">​</a></h1><h3 id="✧-general" tabindex="-1"><a href="#general">✧ General</a> <a class="header-anchor" href="#✧-general" aria-label="Permalink to &quot;[✧ General](#general)&quot;">​</a></h3><ul><li><a href="./faq#piv">Is [plugin] compatible with my After Effects version?</a></li><li><a href="./faq#gcc">How can I resolve &quot;This unlicensed Adobe app will be disabled&quot;?</a></li><li><a href="./faq#swt">What will happen if I switch After Effects versions?</a></li><li><a href="./faq#pdw">What are plugins and which ones should I download?</a></li><li><a href="./faq#rev">Which version of After Effects should I get?</a></li><li><a href="./faq#lsc">Can I download cracked plugins despite having a legitimate software copy?</a></li><li><a href="./faq#wtm">There is a watermark when I use a plugin.</a></li><li><a href="./faq#pdt">My software says it can be updated. Should I click accept?</a></li><li><a href="./faq#dup">I have duplicate effects from a plugin. What do I do?</a></li><li><a href="./faq#eep">I installed an extension (e.g. Flow) that appears in the list, but nothing happens when I click on it.</a></li><li><a href="./faq#gai">Generative AI is not working. Help!</a></li><li><a href="./faq#cep">Missing CEP folder.</a></li><li><a href="./faq#mbl">Magic Bullet Look presets not appearing same as the original coloring.</a></li></ul><h3 id="✧-windows" tabindex="-1"><a href="#windows">✧ Windows</a> <a class="header-anchor" href="#✧-windows" aria-label="Permalink to &quot;[✧ Windows](#windows)&quot;">​</a></h3><ul><li><a href="./faq#wxt">&quot;Windows cannot complete the extraction. The destination file could not be created.&quot;</a></li><li><a href="./faq#cer">&quot;An unexpected error is keeping you from copying the file, Error 0x80004005.&quot;</a></li><li><a href="./faq#ser">&quot;The application was unable to start correctly (Oxc0000142). Click OK to close the application.&quot;</a></li><li><a href="./faq#scp">&quot;The system cannot find the path specified.&quot;</a></li><li><a href="./faq#ect">Error Code: 24 (Adobe)</a></li><li><a href="./faq#erm">&quot;AfterFX.exe - System Error. The code execution cannot proceed because MSVCP110.dll was not found.&quot;</a></li><li><a href="./faq#drs">DaVinci Resolve Studio not starting (Windows).</a></li><li><a href="./faq#imd">&quot;The installation cannot continue as the installer file may be damaged. Download the installer file again.&quot;</a></li><li><a href="./faq#eco">Error Code 127 (Adobe)</a></li><li><a href="./faq#per">&quot;Patching Error - Pattern in Resolve. exe matched 0 times in .text section. Expected exactly 1.&quot;</a></li><li><a href="./faq#wde">Windows Defender is blocking an application from running and I don&#39;t know how to stop it?</a></li><li><a href="./faq#vgl">I’m unable to launch specific games (e.g Valorant) after Adobe installation(s)?</a></li><li><a href="./faq#cfd">DeleteFile failed; code 5. Access is denied. (Red Giant Service.exe)</a></li><li><a href="./faq#fer">&quot;Error copying file from [...] Red Giant Service.exe&quot; (Maxon App)</a></li></ul><h3 id="✧-macos" tabindex="-1"><a href="./faq#macos">✧ MacOS</a> <a class="header-anchor" href="#✧-macos" aria-label="Permalink to &quot;[✧ MacOS](faq#macos)&quot;">​</a></h3><ul><li><a href="./faq#aec">&quot;After Effects can&#39;t continue: unexpected failure during application startup.&quot;</a></li><li><a href="./faq#pci">&quot;The following plugins are installed but are not yet compatible with this version.&quot;</a></li><li><a href="./faq#ddi">&quot;Is damaged and cannot be opened, you should eject the disk image / you should move it to the trash.&quot;</a></li><li><a href="./faq#icc">&quot;The installation cannot continue as the installer file may be damaged. Download the installer file again.&quot;</a></li><li><a href="./faq#xcc">&quot;You don&#39;t have XCode Command Line tools&quot;</a></li><li><a href="./faq#eer">&quot;Error: couldn&#39;t find main entry point&quot;</a></li><li><a href="./faq#ott">Failed with error code 133 (Adobe)</a></li><li><a href="./faq#uid">&quot;Cannot be opened because it is from an unidentified developer&quot; / &quot;because Apple cannot check it for malicious software&quot; / &quot;cannot verify that this app is free from malware.&quot;</a></li><li><a href="./faq#esn">&quot;Unable to expand [X] into &quot; &quot;. (Error 79)&quot;</a></li><li><a href="./faq#ccx">&quot;There was a problem installing CCXProcess&quot;</a></li><li><a href="./faq#pcp">&quot;The file “Patch.command” could not be executed because you do not have appropriate access privileges.&quot;</a></li><li><a href="./faq#uvs">Error creating directory / <em><strong>unknown variable asesupportfilepath 1</strong></em></a></li><li><a href="./faq#ots">Error Code 127 (Adobe)</a></li><li><a href="./faq#jsn">Error: SyntaxError: JSON Parse error: Unexpected EOF (-2700)</a></li><li><a href="./faq#pit">When I type my password in Terminal nothing happens?</a></li><li><a href="./faq#lff">I can&#39;t find my Library folder in Finder.</a></li><li><a href="./faq#ali">&quot;Adobe X wants to access key &quot;Adobe Licensing Information“ in your keychain&quot;</a></li></ul><hr><h2 id="✧-general-1" tabindex="-1">✧ General <span id="general"></span> <a class="header-anchor" href="#✧-general-1" aria-label="Permalink to &quot;✧ General &lt;span id=&quot;general&quot;&gt;&lt;/span&gt;&quot;">​</a></h2><h3 id="is-plugin-compatible-with-my-after-effects-version" tabindex="-1">Is [plugin] compatible with my After Effects version? <span id="piv"></span> <a class="header-anchor" href="#is-plugin-compatible-with-my-after-effects-version" aria-label="Permalink to &quot;Is [plugin] compatible with my After Effects version? &lt;span id=&quot;piv&quot;&gt;&lt;/span&gt;&quot;">​</a></h3><p>The majority of plugins available will work on any standard version of After Effects (2020+). Scripts and extensions will vary; look into their developer notes. <br><br></p><h3 id="how-can-i-resolve-this-unlicensed-adobe-app-will-be-disabled" tabindex="-1">How can I resolve &quot;This unlicensed Adobe app will be disabled&quot;? <span id="gcc"></span> <a class="header-anchor" href="#how-can-i-resolve-this-unlicensed-adobe-app-will-be-disabled" aria-label="Permalink to &quot;How can I resolve &quot;This unlicensed Adobe app will be disabled&quot;? &lt;span id=&quot;gcc&quot;&gt;&lt;/span&gt;&quot;">​</a></h3><p>This alert is fairly common and easily fixable. Click <a href="./aup">here</a> to learn how to remove it. <br><br></p><h3 id="what-will-happen-if-i-switch-after-effects-versions" tabindex="-1">What will happen if I switch After Effects versions? <span id="swt"></span> <a class="header-anchor" href="#what-will-happen-if-i-switch-after-effects-versions" aria-label="Permalink to &quot;What will happen if I switch After Effects versions? &lt;span id=&quot;swt&quot;&gt;&lt;/span&gt;&quot;">​</a></h3><p>Click <a href="./vsg">here</a> to learn how you can make a smooth transition when upgrading versions without losing any of your plugins or presets. It&#39;s easier than you might think. <br><br></p><h3 id="what-are-plugins-and-which-ones-should-i-download" tabindex="-1">What are plugins and which ones should I download? <span id="pdw"></span> <a class="header-anchor" href="#what-are-plugins-and-which-ones-should-i-download" aria-label="Permalink to &quot;What are plugins and which ones should I download? &lt;span id=&quot;pdw&quot;&gt;&lt;/span&gt;&quot;">​</a></h3><p>Click <a href="./bgtae">here</a> for starter recommendations. Ultimately, it entirely depends on your style. <br><br></p><h3 id="which-version-of-after-effects-should-i-get" tabindex="-1">Which version of After Effects should I get? <span id="rev"></span> <a class="header-anchor" href="#which-version-of-after-effects-should-i-get" aria-label="Permalink to &quot;Which version of After Effects should I get? &lt;span id=&quot;rev&quot;&gt;&lt;/span&gt;&quot;">​</a></h3><p>The newest version (features) is always worth getting as long as you have enough RAM and a good CPU, click <a href="./bgtae">here</a> for more information. <br><br></p><h3 id="can-i-download-cracked-plugins-despite-having-a-legitimate-software-copy" tabindex="-1">Can I download cracked plugins despite having a legitimate software copy? <span id="lsc"></span> <a class="header-anchor" href="#can-i-download-cracked-plugins-despite-having-a-legitimate-software-copy" aria-label="Permalink to &quot;Can I download cracked plugins despite having a legitimate software copy? &lt;span id=&quot;lsc&quot;&gt;&lt;/span&gt;&quot;">​</a></h3><p>Yes. Why are you paying for it, though? <br><br></p><h3 id="there-is-a-watermark-when-i-use-a-plugin" tabindex="-1">There is a watermark when I use a plugin. <span id="wtm"></span> <a class="header-anchor" href="#there-is-a-watermark-when-i-use-a-plugin" aria-label="Permalink to &quot;There is a watermark when I use a plugin. &lt;span id=&quot;wtm&quot;&gt;&lt;/span&gt;&quot;">​</a></h3><p>A watermark, typically a red X means that whatever plugin you&#39;re using is unlicensed. This indicates you did not install it properly. Make sure to properly read the instructions or refer to our support server for assistance. <br><br></p><h3 id="my-software-says-it-can-be-updated-should-i-click-accept" tabindex="-1">My software says it can be updated. Should I click accept? <span id="pdt"></span> <a class="header-anchor" href="#my-software-says-it-can-be-updated-should-i-click-accept" aria-label="Permalink to &quot;My software says it can be updated. Should I click accept? &lt;span id=&quot;pdt&quot;&gt;&lt;/span&gt;&quot;">​</a></h3><p>No, these are official pop-ups. The software will no longer be licensed if you do so. <br><br></p><h3 id="i-have-duplicate-effects-from-a-plugin-what-do-i-do" tabindex="-1">I have duplicate effects from a plugin. What do I do? <span id="dup"></span> <a class="header-anchor" href="#i-have-duplicate-effects-from-a-plugin-what-do-i-do" aria-label="Permalink to &quot;I have duplicate effects from a plugin. What do I do? &lt;span id=&quot;dup&quot;&gt;&lt;/span&gt;&quot;">​</a></h3><p>This indicates you have two versions of a plugin installed, or in different locations. Choose and delete one of the paths shown in your error. For example, Sapphire:</p><p><code>C:\\Program Files\\Adobe\\Common\\Plug-ins\\7.0\\MediaCore\\Sapphire Plug-ins</code></p><p><code>C:\\Program Files\\Adobe\\Common\\Plug-ins\\7.0\\MediaCore\\BorisFX\\Sapphire Plug-ins</code></p><p>You can either delete one of these folders, though, consider removing both of them and reinstalling if you&#39;re attempting to upgrade a plugin to be safe. <br><br></p><h3 id="i-installed-an-extension-e-g-flow-that-appears-in-the-list-but-nothing-happens-when-i-click-on-it" tabindex="-1">I installed an extension (e.g. Flow) that appears in the list, but nothing happens when I click on it. <span id="eep"></span> <a class="header-anchor" href="#i-installed-an-extension-e-g-flow-that-appears-in-the-list-but-nothing-happens-when-i-click-on-it" aria-label="Permalink to &quot;I installed an extension (e.g. Flow) that appears in the list, but nothing happens when I click on it. &lt;span id=&quot;eep&quot;&gt;&lt;/span&gt;&quot;">​</a></h3><p>Ensure that the CEP (Common Extensibility Platform) is enabled.</p><p><span style="font-weight:800;">Windows</span>:</p><ol><li>Close After Effects.</li><li>Download this <a href="https://www.mediafire.com/file/ak5jdd2y6z2si09/keys.reg/file" target="_blank" rel="noreferrer">file</a> and run it.</li></ol><p><span style="font-weight:800;">Mac</span>:</p><ol><li>Close After Effects and open Terminal.</li><li>Copy and paste the text below:</li></ol><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">defaults write com.adobe.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">CSXS</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">10</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> PlayerDebugMode </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">defaults write com.adobe.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">CSXS</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">11</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> PlayerDebugMode </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">defaults write com.adobe.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">CSXS</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">12</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> PlayerDebugMode </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">defaults write com.adobe.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">CSXS</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">13</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> PlayerDebugMode </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span></span></code></pre></div><ol start="3"><li>Hit enter and you&#39;re done. <br><br></li></ol><h3 id="generative-ai-is-not-working-help" tabindex="-1">Generative AI is not working. Help! <span id="gai"></span> <a class="header-anchor" href="#generative-ai-is-not-working-help" aria-label="Permalink to &quot;Generative AI is not working. Help! &lt;span id=&quot;gai&quot;&gt;&lt;/span&gt;&quot;">​</a></h3><p>AI Tools such as Generative Fill will not work on cracked versions of Photoshop due to the fact that Adobe uses a credit system for verification specifically for it. <br><br></p><h3 id="missing-cep-folder" tabindex="-1">Missing CEP folder.<span id="cep"></span> <a class="header-anchor" href="#missing-cep-folder" aria-label="Permalink to &quot;Missing CEP folder.&lt;span id=&quot;cep&quot;&gt;&lt;/span&gt;&quot;">​</a></h3><p>Make sure your installation isn’t faulty, and that scripting and expressions are enabled in After Effects.</p><p>Open After Effects and enable “Allow Scripts to Write Files and Access Network”.</p><p>Windows: <code>Edit &gt; Preferences &gt; Scripting &amp; Expressions</code></p><p>Mac: <code>After Effects &gt; Preferences &gt; Scripting &amp; Expressions</code></p><p><span style="font-weight:800;">Create the CEP folder manually</span>:</p><p>Go to the location below and create a <strong>CEP</strong> folder, and inside that CEP folder, create another folder named <strong>Extensions</strong>.</p><p>Windows: <code>C:\\Program Files (x86)\\Common Files\\Adobe</code></p><p>Mac: <code>/Library/Application Support/Adobe/</code><br><br></p><h3 id="magic-bullet-look-presets-not-appearing-same-as-the-original-coloring" tabindex="-1">Magic Bullet Look presets not appearing same as the original coloring. <span id="mbl"></span> <a class="header-anchor" href="#magic-bullet-look-presets-not-appearing-same-as-the-original-coloring" aria-label="Permalink to &quot;Magic Bullet Look presets not appearing same as the original coloring. &lt;span id=&quot;mbl&quot;&gt;&lt;/span&gt;&quot;">​</a></h3><p>Many Looks Builder tools were updated in the 2025 release, causing older presets to appear overexposured.</p><ol><li>Open Looks Builder.</li><li>At the top at &quot;In/Out Color Space&quot;, press the dropdown menu.</li><li>Select &quot;1D sRGB (Video)&quot;</li></ol><hr><h2 id="✧-windows-1" tabindex="-1">✧ Windows <span id="windows"></span> <a class="header-anchor" href="#✧-windows-1" aria-label="Permalink to &quot;✧ Windows &lt;span id=&quot;windows&quot;&gt;&lt;/span&gt;&quot;">​</a></h2><h3 id="windows-cannot-complete-the-extraction-the-destination-file-could-not-be-created" tabindex="-1">&quot;Windows cannot complete the extraction. The destination file could not be created.&quot; <span id="wxt"></span> <a class="header-anchor" href="#windows-cannot-complete-the-extraction-the-destination-file-could-not-be-created" aria-label="Permalink to &quot;&quot;Windows cannot complete the extraction. The destination file could not be created.&quot; &lt;span id=&quot;wxt&quot;&gt;&lt;/span&gt;&quot;">​</a></h3><p>This error occurs if a file hasn&#39;t been properly extracted. Please follow the instructions written in the <a href="./xtr">extraction page</a> regarding how to use 7-Zip. <br><br></p><h3 id="an-unexpected-error-is-keeping-you-from-copying-the-file-error-0x80004005" tabindex="-1">&quot;An unexpected error is keeping you from copying the file, Error 0x80004005.&quot; <span id="cer"></span> <a class="header-anchor" href="#an-unexpected-error-is-keeping-you-from-copying-the-file-error-0x80004005" aria-label="Permalink to &quot;&quot;An unexpected error is keeping you from copying the file, Error 0x80004005.&quot; &lt;span id=&quot;cer&quot;&gt;&lt;/span&gt;&quot;">​</a></h3><p>This error occurs if a file hasn&#39;t been properly extracted. Please follow the instructions written in the <a href="./xtr">extraction page</a> regarding how to use 7-Zip. <br><br></p><h3 id="the-application-was-unable-to-start-correctly-oxc0000142-click-ok-to-close-the-application" tabindex="-1">&quot;The application was unable to start correctly (Oxc0000142). Click OK to close the application.&quot; <span id="ser"></span> <a class="header-anchor" href="#the-application-was-unable-to-start-correctly-oxc0000142-click-ok-to-close-the-application" aria-label="Permalink to &quot;&quot;The application was unable to start correctly (Oxc0000142). Click OK to close the application.&quot; &lt;span id=&quot;ser&quot;&gt;&lt;/span&gt;&quot;">​</a></h3><p>Starting from version 24.1, <strong>After Effects requires your processor to support Advanced Vector Extensions 2</strong> or else the software will not launch.</p><p>If your processor does not support AVX2, <strong>you&#39;ll need to downgrade to AE 2023 or lower</strong>. <br><br></p><h3 id="the-system-cannot-find-the-path-specified" tabindex="-1">&quot;The system cannot find the path specified.&quot; <span id="scp"></span> <a class="header-anchor" href="#the-system-cannot-find-the-path-specified" aria-label="Permalink to &quot;&quot;The system cannot find the path specified.&quot; &lt;span id=&quot;scp&quot;&gt;&lt;/span&gt;&quot;">​</a></h3><p>Move the folder to your desktop and try again. If that does not work, remove the &quot;/&quot; symbol from the folder name if included. <br><br></p><h3 id="error-code-24-adobe" tabindex="-1">Error Code: 24 (Adobe) <span id="ect"></span> <a class="header-anchor" href="#error-code-24-adobe" aria-label="Permalink to &quot;Error Code: 24 (Adobe) &lt;span id=&quot;ect&quot;&gt;&lt;/span&gt;&quot;">​</a></h3><ul><li>Extract the iso file itself (Right click &gt; 7-Zip &gt; Extract here)</li><li>Temporarily turn off your internet.</li><li>Open the extracted folder and run Set-up.exe again. <br><br></li></ul><h3 id="afterfx-exe-system-error-the-code-execution-cannot-proceed-because-msvcp110-dll-was-not-found" tabindex="-1">&quot;AfterFX.exe - System Error. The code execution cannot proceed because MSVCP110.dll was not found.&quot; <span id="erm"></span> <a class="header-anchor" href="#afterfx-exe-system-error-the-code-execution-cannot-proceed-because-msvcp110-dll-was-not-found" aria-label="Permalink to &quot;&quot;AfterFX.exe - System Error. The code execution cannot proceed because MSVCP110.dll was not found.&quot; &lt;span id=&quot;erm&quot;&gt;&lt;/span&gt;&quot;">​</a></h3><p>Your computer is missing necessary components. Install the <a href="https://learn.microsoft.com/en-us/cpp/windows/latest-supported-vc-redist" target="_blank" rel="noreferrer">Microsoft Visual C++ Redistributables</a> and restart your computer. <br><br></p><h3 id="davinci-resolve-studio-not-starting-windows" tabindex="-1">DaVinci Resolve Studio not starting (Windows). <span id="drs"></span> <a class="header-anchor" href="#davinci-resolve-studio-not-starting-windows" aria-label="Permalink to &quot;DaVinci Resolve Studio not starting (Windows). &lt;span id=&quot;drs&quot;&gt;&lt;/span&gt;&quot;">​</a></h3><p>Rename OFX folder &quot;Plugins&quot; (<code>C:\\Program Files\\Common Files\\OFX</code>) to &quot;Plugins.origin&quot;. <br><br></p><h3 id="the-installation-cannot-continue-as-the-installer-file-may-be-damaged-download-the-installer-file-again" tabindex="-1">&quot;The installation cannot continue as the installer file may be damaged. Download the installer file again.&quot; <span id="imd"></span> <a class="header-anchor" href="#the-installation-cannot-continue-as-the-installer-file-may-be-damaged-download-the-installer-file-again" aria-label="Permalink to &quot;&quot;The installation cannot continue as the installer file may be damaged. Download the installer file again.&quot; &lt;span id=&quot;imd&quot;&gt;&lt;/span&gt;&quot;">​</a></h3><p>This error occurs if a file hasn&#39;t been properly extracted. Please follow the instructions written in the <a href="./xtr">extraction page</a> regarding how to use 7-Zip.</p><p>If it is properly extracted, it may mean you have leftovers from a previous installation. Use the official <a href="AdobeCreativeCloudCleanerTool.exe">Adobe Creative Cloud Cleaner Tool</a> to get rid of previous installations. <br><br></p><h3 id="error-code-127-adobe" tabindex="-1">Error Code 127 (Adobe) <span id="eco"></span> <a class="header-anchor" href="#error-code-127-adobe" aria-label="Permalink to &quot;Error Code 127 (Adobe) &lt;span id=&quot;eco&quot;&gt;&lt;/span&gt;&quot;">​</a></h3><p><a href="https://helpx.adobe.com/creative-cloud/kb/troubleshoot-download-install-logs.html#error127" target="_blank" rel="noreferrer">Error code 127</a> indicates that the installer isn&#39;t able to extract the zip file in the <code>adobeTemp</code> folder. This can happen due to a lack of disk space or if the necessary permissions are unavailable. Sometimes, even antivirus software can block the extraction process in the temp directory.</p><ol><li>Navigate to the <code>adobetemp</code> folder located at <code>&lt;Root Drive&gt;\\adobeTemp</code>. In the following example, the root drive is the C: drive.</li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>If the folder doesn&#39;t exist, you can also create the folder.</p></div><ol start="2"><li>Right click anywhere on screen &gt; <strong>Properties</strong>.</li><li>In the <strong>Security</strong> tab, ensure that permissions for <strong>System</strong> and <strong>Administrators</strong> have <strong>Full Control</strong>.</li><li>Turn off your antivirus temporarily or whitelist it. <br><br></li></ol><h3 id="patching-error-pattern-in-resolve-exe-matched-0-times-in-text-section-expected-exactly-1" tabindex="-1">&quot;Patching Error - Pattern in Resolve. exe matched 0 times in .text section. Expected exactly 1.&quot; <span id="per"></span> <a class="header-anchor" href="#patching-error-pattern-in-resolve-exe-matched-0-times-in-text-section-expected-exactly-1" aria-label="Permalink to &quot;&quot;Patching Error - Pattern in Resolve. exe matched 0 times in .text section. Expected exactly 1.&quot; &lt;span id=&quot;per&quot;&gt;&lt;/span&gt;&quot;">​</a></h3><p>This error occurs when a user mistakenly installs the free version of DaVinci Resolve and then runs our patch, which is intended for the <strong>Studio</strong> version. Ensure that you install the correct version. <br><br></p><h3 id="windows-defender-is-blocking-an-application-from-running-and-i-don-t-know-how-to-stop-it" tabindex="-1">Windows Defender is blocking an application from running and I don&#39;t know how to stop it? <span id="wde"></span> <a class="header-anchor" href="#windows-defender-is-blocking-an-application-from-running-and-i-don-t-know-how-to-stop-it" aria-label="Permalink to &quot;Windows Defender is blocking an application from running and I don&#39;t know how to stop it? &lt;span id=&quot;wde&quot;&gt;&lt;/span&gt;&quot;">​</a></h3><p>You can either exclude or whitelist the file, disabling Defender completely is not recommended.</p><p><span style="font-weight:800;">Exclude</span><span class="note" style="display:inline-block;margin-left:8px;"><a href="https://files.catbox.moe/jnwuuc.mp4" target="_blank" rel="noreferrer">Video Tutorial</a></span></p><ol><li>Click the Windows key and write &quot;Settings&quot;.</li><li>Go to <strong>Privacy &amp; security</strong> &gt; <strong>Windows Security</strong> &gt; <strong>Virus &amp; Threat Protection</strong>.</li><li>Under <strong>Virus &amp; Threat Protection</strong> settings, click <strong>Manage settings</strong>.</li><li>Under <strong>Exclusions</strong>, click on <strong>Add or remove exclusions</strong>.</li><li>Choose your installer/installation folder.</li></ol><p><span style="font-weight:800;">Whitelist</span><span class="note" style="display:inline-block;margin-left:8px;"><a href="https://files.catbox.moe/uczy2z.mp4" target="_blank" rel="noreferrer">Video Tutorial</a></span></p><ol><li>Open <strong>Virus &amp; Threat Protection</strong>.</li><li>When the blocked file shows up under current threats, click it and on <strong>Action options</strong>, select <strong>Allow on device</strong>.</li><li>Finalize decision by pressing <strong>Start actions</strong>. <br><br></li></ol><h3 id="i-m-unable-to-launch-specific-games-e-g-valorant-after-adobe-installation-s" tabindex="-1">I’m unable to launch specific games (e.g Valorant) after Adobe installation(s)? <span id="vgl"></span> <a class="header-anchor" href="#i-m-unable-to-launch-specific-games-e-g-valorant-after-adobe-installation-s" aria-label="Permalink to &quot;I’m unable to launch specific games (e.g Valorant) after Adobe installation(s)? &lt;span id=&quot;vgl&quot;&gt;&lt;/span&gt;&quot;">​</a></h3><p>If after installation you start having problems with programs and games that worked fine before, simply delete the following registry key:</p><p><code>HKEY_LOCAL_MACHINE\\SOFTWARE\\Microsoft\\Windows NT\\CurrentVersion\\Image File Execution Options\\DevOverrideEnable</code></p><p>then reboot your system. <span class="note">If using GenP, you will have a toggle in-app for the Registry Key.</span> Certain games and other sensitive apps that use anti-cheat mechanisms may detect and flag DLL redirection as suspicious activity which may result in false positives. <br><br></p><h3 id="deletefile-failed-code-5-access-is-denied-red-giant-service-exe" tabindex="-1">DeleteFile failed; code 5. Access is denied. (Red Giant Service.exe) <span id="cfd"></span> <a class="header-anchor" href="#deletefile-failed-code-5-access-is-denied-red-giant-service-exe" aria-label="Permalink to &quot;DeleteFile failed; code 5. Access is denied. (Red Giant Service.exe) &lt;span id=&quot;cfd&quot;&gt;&lt;/span&gt;&quot;">​</a></h3><ol><li>Open <strong>Task Manager</strong> <em>(Ctrl+Shift+Esc)</em>.</li><li>Search <strong>Red Giant Service</strong> and <strong>MxNotify</strong>.</li><li><strong>Right click</strong> &gt; <strong>End tasks</strong>.</li><li>Try again. <br><br></li></ol><h3 id="error-copying-file-from-red-giant-service-exe-maxon-app" tabindex="-1">&quot;Error copying file from [...] Red Giant Service.exe&quot; (Maxon App) <span id="fer"></span> <a class="header-anchor" href="#error-copying-file-from-red-giant-service-exe-maxon-app" aria-label="Permalink to &quot;&quot;Error copying file from [...] Red Giant Service.exe&quot; (Maxon App) &lt;span id=&quot;fer&quot;&gt;&lt;/span&gt;&quot;">​</a></h3><ol><li>Open <strong>Task Manager</strong> <em>(Ctrl+Shift+Esc)</em>.</li><li>Search <strong>Red Giant Service</strong> and <strong>MxNotify</strong>.</li><li><strong>Right click</strong> &gt; <strong>End tasks</strong>.</li><li>Try again.</li></ol><hr><h2 id="✧-macos-1" tabindex="-1">✧ MacOS <span id="macos"></span> <a class="header-anchor" href="#✧-macos-1" aria-label="Permalink to &quot;✧ MacOS &lt;span id=&quot;macos&quot;&gt;&lt;/span&gt;&quot;">​</a></h2><div style="background-color:#302e2e;padding:16px;border-radius:6px;"> Common questions and troubleshooting for issues on Mac. </div><br><h3 id="after-effects-can-t-continue-unexpected-failure-during-application-startup" tabindex="-1">&quot;After Effects can&#39;t continue: unexpected failure during application startup.&quot; <span id="aec"></span> <a class="header-anchor" href="#after-effects-can-t-continue-unexpected-failure-during-application-startup" aria-label="Permalink to &quot;&quot;After Effects can&#39;t continue: unexpected failure during application startup.&quot; &lt;span id=&quot;aec&quot;&gt;&lt;/span&gt;&quot;">​</a></h3><p>After Effects 2021 and below are not compatible with OS14 and higher. You won’t be able to launch these versions of After Effects. Your only option is to install After Effects 2022 or newer. <span class="note">If this appears on 2022+, refer to <a href="https://community.adobe.com/bug-reports-528/after-effects-23-6-and-24-0-not-starting-on-macos-14-sonoma-1216945#comments" target="_blank" rel="noreferrer">this</a></span><br></p><h3 id="the-following-plugins-are-installed-but-are-not-yet-compatible-with-this-version" tabindex="-1">&quot;The following plugins are installed but are not yet compatible with this version&quot;. <span id="pci"></span> <a class="header-anchor" href="#the-following-plugins-are-installed-but-are-not-yet-compatible-with-this-version" aria-label="Permalink to &quot;&quot;The following plugins are installed but are not yet compatible with this version&quot;. &lt;span id=&quot;pci&quot;&gt;&lt;/span&gt;&quot;">​</a></h3><p>This issue occurs when a user installs an outdated plugin only designed for Intel Macs on After Effects that is running natively on Apple Silicon (M1+ on After Effects 2022+).</p><p>Only a small number of plugins on this site are not supported, click <a href="./ros">here</a> for a more in-depth explanation and assistance on your choices moving forward. <br><br></p><h3 id="is-damaged-and-cannot-be-opened-you-should-eject-the-disk-image-you-should-move-it-to-the-trash" tabindex="-1">&quot;Is damaged and cannot be opened, you should eject the disk image / you should move it to the trash.&quot; <span id="ddi"></span> <a class="header-anchor" href="#is-damaged-and-cannot-be-opened-you-should-eject-the-disk-image-you-should-move-it-to-the-trash" aria-label="Permalink to &quot;&quot;Is damaged and cannot be opened, you should eject the disk image / you should move it to the trash.&quot; &lt;span id=&quot;ddi&quot;&gt;&lt;/span&gt;&quot;">​</a></h3><p><span style="font-weight:800;">If the error occurs when running an application file</span>:</p><ol><li>Drag the installer to your desktop, open Terminal and input <code>sudo xattr -cr</code>.</li><li>Drag the installer file next to the command. <strong>There must be a space between the command and the file</strong>. Hit <strong>Enter</strong> and submit your Mac password. Passwords are not displayed when typed into Terminal, so you won&#39;t see this.</li></ol><p><span style="font-weight:800;">If a plugin shows this error inside After Effects</span>:</p><ol><li>Open Terminal and input <code>sudo xattr -rd com.apple.quarantine</code>.</li><li>Drag the plugin file next to the command, <strong>there must be a space between the command and the file</strong>.</li><li>Hit enter and submit your Mac password. Passwords are not displayed when typed into Terminal, you wont see this.</li></ol><p>Still having issues? Try using <a href="https://itsalin.com/appInfo/?id=sentinel" target="_blank" rel="noreferrer">Sentinel</a> to solve the problem. <br><br></p><h3 id="the-installation-cannot-continue-as-the-installer-file-may-be-damaged-download-the-installer-file-again-1" tabindex="-1">&quot;The installation cannot continue as the installer file may be damaged. Download the installer file again.&quot; <span id="icc"></span> <a class="header-anchor" href="#the-installation-cannot-continue-as-the-installer-file-may-be-damaged-download-the-installer-file-again-1" aria-label="Permalink to &quot;&quot;The installation cannot continue as the installer file may be damaged. Download the installer file again.&quot; &lt;span id=&quot;icc&quot;&gt;&lt;/span&gt;&quot;">​</a></h3><p><strong>Right Click</strong> &gt; <strong>Show Package Contents</strong> &gt; <strong>Contents</strong> &gt; <strong>MacOS</strong> &gt; <strong>Install</strong>. <br><br></p><h3 id="you-don-t-have-xcode-command-line-tools" tabindex="-1">&quot;You don&#39;t have XCode Command Line tools&quot; <span id="xcc"></span> <a class="header-anchor" href="#you-don-t-have-xcode-command-line-tools" aria-label="Permalink to &quot;&quot;You don&#39;t have XCode Command Line tools&quot; &lt;span id=&quot;xcc&quot;&gt;&lt;/span&gt;&quot;">​</a></h3><ul><li>Monters &quot;23.6 fix.pkg&quot; is unsupported on Sonoma, causing this error. You won&#39;t be able to run it.</li></ul><p>You can download and run this alternative <a href="https://www.mediafire.com/file/xp67w6dfdfqtb6s/ADOBE_23.6_FIX_-_SATVRN.zip/file" target="_blank" rel="noreferrer">patcher</a> instead. Instructions are included. <br><br></p><h3 id="eer" tabindex="-1">Error: couldn&#39;t find main entry point <a class="header-anchor" href="#eer" aria-label="Permalink to &quot;Error: couldn&#39;t find main entry point {#eer}&quot;">​</a></h3><p>This typically means the plugin you&#39;re trying to run is missing a key file it needs to start, or it’s not installed correctly. Refer to text instructions and/or visual guides and reinstall it from scratch. <span class="note">If seeing this with Twixtor 8, use the RE:Vision 2303 Bundle.</span><span style="font-weight:800;">Last Resort: Disable Gatekeeper</span></p><p>Use <a href="https://itsalin.com/appInfo/?id=sentinel" target="_blank" rel="noreferrer">Sentinel</a> to sign the plugin or disable gatekeeper, proceed with caution. <br><br></p><h3 id="failed-with-error-code-133-adobe" tabindex="-1">Failed with error code 133 (Adobe) <span id="ott"></span> <a class="header-anchor" href="#failed-with-error-code-133-adobe" aria-label="Permalink to &quot;Failed with error code 133 (Adobe) &lt;span id=&quot;ott&quot;&gt;&lt;/span&gt;&quot;">​</a></h3><p>Error 133 indicates insufficient disk space to download and install the applications. Free up some space or select another location for your app and try again. <br><br></p><h3 id="cannot-be-opened-because-it-is-from-an-unidentified-developer-because-apple-cannot-check-it-for-malicious-software-cannot-verify-that-this-app-is-free-from-malware" tabindex="-1">&quot;Cannot be opened because it is from an unidentified developer&quot; / &quot;because Apple cannot check it for malicious software&quot; / &quot;cannot verify that this app is free from malware.&quot; <span id="uid"></span> <a class="header-anchor" href="#cannot-be-opened-because-it-is-from-an-unidentified-developer-because-apple-cannot-check-it-for-malicious-software-cannot-verify-that-this-app-is-free-from-malware" aria-label="Permalink to &quot;&quot;Cannot be opened because it is from an unidentified developer&quot; / &quot;because Apple cannot check it for malicious software&quot; / &quot;cannot verify that this app is free from malware.&quot; &lt;span id=&quot;uid&quot;&gt;&lt;/span&gt;&quot;">​</a></h3><p>By default, macOS blocks most apps that aren’t from the App Store and lack signatures, even if they’re completely safe.</p><p><span style="font-weight:800;">If the error occurs when attempting to run any sort of dmg or pkg file</span>:</p><ol><li><strong>Right-click</strong> the file <em>(hold <strong>Control</strong> and <strong>click</strong> the file to bring up the menu)</em></li><li>Select <strong>Open</strong></li><li>It will show a warning, but this time it will give you an <strong>Open Anyway</strong> button.</li></ol><p><span style="font-weight:800;">If the error occurs for a plugin</span>:</p><ol><li>Click the <strong>Apple logo</strong> in the top left corner</li><li>Go to <strong>System Settings</strong></li><li>Open <strong>Security &amp; Privacy</strong></li><li>At the bottom of the window, look for a message saying the app/plugin was blocked</li><li>Click <strong>Allow Anyway</strong><span class="note">You might need to unlock settings by clicking the lock icon in the bottom left corner, and then entering your password.</span></li></ol><p>Still having issues? Try using <a href="https://itsalin.com/appInfo/?id=sentinel" target="_blank" rel="noreferrer">Sentinel</a> to sign or unblock the app. <br><br></p><h3 id="unable-to-expand-x-into-error-79" tabindex="-1">&quot;Unable to expand [X] into &quot; &quot;. (Error 79)&quot; <span id="esn"></span> <a class="header-anchor" href="#unable-to-expand-x-into-error-79" aria-label="Permalink to &quot;&quot;Unable to expand [X] into &quot; &quot;. (Error 79)&quot; &lt;span id=&quot;esn&quot;&gt;&lt;/span&gt;&quot;">​</a></h3><p>This error occurs if a file hasn&#39;t been properly extracted. Please follow the instructions written in the <a href="./xtr">extraction page</a> regarding how to use Keka. <br><br></p><h3 id="there-was-a-problem-installing-ccxprocess" tabindex="-1">&quot;There was a problem installing CCXProcess&quot; <span id="ccx"></span> <a class="header-anchor" href="#there-was-a-problem-installing-ccxprocess" aria-label="Permalink to &quot;&quot;There was a problem installing CCXProcess&quot; &lt;span id=&quot;ccx&quot;&gt;&lt;/span&gt;&quot;">​</a></h3><ol><li>Open Terminal</li><li>Copy and paste <code>sudo softwareupdate --install-rosetta --agree-to-license</code>.</li><li>Press enter. After Rosetta is installed, run the Adobe installer again. <br><br></li></ol><h3 id="the-file-patch-command-could-not-be-executed-because-you-do-not-have-appropriate-access-privileges" tabindex="-1">&quot;The file “Patch.command” could not be executed because you do not have appropriate access privileges.&quot; <span id="pcp"></span> <a class="header-anchor" href="#the-file-patch-command-could-not-be-executed-because-you-do-not-have-appropriate-access-privileges" aria-label="Permalink to &quot;&quot;The file “Patch.command” could not be executed because you do not have appropriate access privileges.&quot; &lt;span id=&quot;pcp&quot;&gt;&lt;/span&gt;&quot;">​</a></h3><ol><li>Open <strong>Terminal</strong>.</li><li>Input <code>chmod +x</code>.</li><li>Insert a space after the command.</li><li>Drop the file into <strong>Terminal</strong>.</li><li>Click on the Terminal window, and then press <strong>Return</strong>. <br><br></li></ol><h3 id="error-creating-directory-unknown-variable-asesupportfilepath-1" tabindex="-1">Error creating directory / <em><strong>unknown variable asesupportfilepath 1</strong></em> <span id="uvs"></span> <a class="header-anchor" href="#error-creating-directory-unknown-variable-asesupportfilepath-1" aria-label="Permalink to &quot;Error creating directory / ***unknown variable asesupportfilepath 1*** &lt;span id=&quot;uvs&quot;&gt;&lt;/span&gt;&quot;">​</a></h3><p>This error can appear when attempting to install Maxon plugins.</p><ol><li>Click <strong>Abort</strong></li><li>Open <strong>Terminal</strong></li><li>Input the following:</li></ol><p><code>sudo sh /Volumes/Red\\ Giant\\ Installer/Red\\ Giant\\ Installer.app/Contents/MacOS/installbuilder.sh --mode text</code></p><ol start="4"><li>Enter you password when prompted, and then hit <strong>Y</strong> if prompted.</li></ol><h3 id="error-code-127-adobe-1" tabindex="-1">Error Code 127 (Adobe) <span id="ots"></span> <a class="header-anchor" href="#error-code-127-adobe-1" aria-label="Permalink to &quot;Error Code 127 (Adobe) &lt;span id=&quot;ots&quot;&gt;&lt;/span&gt;&quot;">​</a></h3><p><a href="https://helpx.adobe.com/creative-cloud/kb/troubleshoot-download-install-logs.html#error127" target="_blank" rel="noreferrer">Error code 127</a> indicates that the installer isn&#39;t able to extract the zip file in the <code>adobeTemp</code> folder. This can happen due to a lack of disk space or if the necessary permissions are unavailable. Sometimes, even antivirus software can block the extraction process in the temp directory.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Open the folder where you want to see the hidden files, and select &quot;Command&quot;+&quot;Shift&quot;+&quot;.&quot; keys simultaneously.</p></div><ol><li>Navigate to the folder located at: <code>/System/Volumes/&lt;Root Drive&gt;/.adobeTemp</code>.</li><li>Go to <strong>File</strong> &gt; <strong>Get Info</strong>, then select <strong>Sharing &amp; Permissions</strong>.</li><li>Select system from the Name column. Ensure that is has <strong>Read &amp; Write</strong> privileges.</li><li>Turn off your antivirus temporarily or whitelist it. You can also free up some space and retry. <br><br></li></ol><h3 id="error-syntaxerror-json-parse-error-unexpected-eof-2700" tabindex="-1">Error: SyntaxError: JSON Parse error: Unexpected EOF (-2700) <span id="jsn"></span> <a class="header-anchor" href="#error-syntaxerror-json-parse-error-unexpected-eof-2700" aria-label="Permalink to &quot;Error: SyntaxError: JSON Parse error: Unexpected EOF (-2700) &lt;span id=&quot;jsn&quot;&gt;&lt;/span&gt;&quot;">​</a></h3><ol><li>Uninstall Creative Cloud with the <a href="https://helpx.adobe.com/creative-cloud/apps/troubleshoot/diagnostics-repair-tools/prepare-to-run-creative-cloud-cleaner-tool.html" target="_blank" rel="noreferrer">Creative Cloud Cleaner Tool</a>.</li><li>Navigate to: <code>/Library/Application Support/Adobe/</code> and <strong>delete</strong> the folder <strong>Caps</strong>. <span class="note">This folder stores installation records; if they’re corrupt, the installer crashes.</span></li><li>Reinstall again. <br><br></li></ol><h3 id="when-i-type-my-password-in-terminal-nothing-happens" tabindex="-1">When I type my password in Terminal nothing happens? <span id="pit"></span> <a class="header-anchor" href="#when-i-type-my-password-in-terminal-nothing-happens" aria-label="Permalink to &quot;When I type my password in Terminal nothing happens? &lt;span id=&quot;pit&quot;&gt;&lt;/span&gt;&quot;">​</a></h3><p>For security purposes your password is completely hidden in <strong>Terminal</strong>, type the password to unlock your Mac and hit <strong>Enter</strong> as normal. <br><br></p><h3 id="i-can-t-find-my-library-folder-in-finder" tabindex="-1">I can&#39;t find my Library folder in Finder. <span id="lff"></span> <a class="header-anchor" href="#i-can-t-find-my-library-folder-in-finder" aria-label="Permalink to &quot;I can&#39;t find my Library folder in Finder. &lt;span id=&quot;lff&quot;&gt;&lt;/span&gt;&quot;">​</a></h3><p>Library is hidden by default on Mac. To enable it, do this:</p><ol><li>Open Finder.</li><li>In the top left go to <strong>Settings</strong> &gt; <strong>Sidebar</strong> &gt; <strong>Enable Hard Disks</strong>.</li></ol><p>Now you&#39;ll find <strong>Macintosh</strong> on the left sidebar, and inside, your <strong>Library</strong>. <br><br></p><h3 id="adobe-x-wants-to-access-key-adobe-licensing-information-in-your-keychain" tabindex="-1">&quot;Adobe X wants to access key &quot;Adobe Licensing Information“ in your keychain&quot; <span id="ali"></span> <a class="header-anchor" href="#adobe-x-wants-to-access-key-adobe-licensing-information-in-your-keychain" aria-label="Permalink to &quot;&quot;Adobe X wants to access key &quot;Adobe Licensing Information“ in your keychain&quot; &lt;span id=&quot;ali&quot;&gt;&lt;/span&gt;&quot;">​</a></h3><p>Either submlit the password used to unlock your Mac and click allow, or deny.</p><p>If notification persists often, run this <a href="https://www.mediafire.com/file/36i034ldsmdiact/Adobe_Keychain_Fixer_v0_15_Monter_Group.dmg/file" target="_blank" rel="noreferrer">dmg file</a>.</p>`,151)])])}const f=t(n,[["render",r]]);export{u as __pageData,f as default};
